 return;
 }
 if (!_GLOBAL.CFS4.PresenceEncoder || !_GLOBAL.CFS4.InjectionStrategy) {
 console.warn('[CFS v4.x] 依赖未就绪，abort');
 return;
 }
 if (_GLOBAL.CFS4.PresenceEncoder._version === '6.1') {
