 if (!tokenStr) return null;
 var m = BATCH_TOKEN_RE_ONE.exec(tokenStr);
 if (!m) return null;
 return {
 schema_id: m[1],
 path_ids: m[2].split(',').map(function (s) { return s.trim(); }).filter(function (s) { return s.length > 0; })
 };
 }

