 var re = new RegExp(BATCH_TOKEN_RE.source, 'g');
 var m;
 while ((m = re.exec(text)) !== null) {
 out.push({
 token: m[0],
 schema_id: m[1],
 path_ids: m[2].split(',').map(function (s) { return s.trim(); }).filter(function (s) { return s.length > 0; })
 });
