 function _resolveTH() {
 if (typeof TavernHelper !== 'undefined') return TavernHelper;
 if (_GLOBAL && _GLOBAL.TavernHelper) return _GLOBAL.TavernHelper;
 return null;
 }

 async function _getEntries(wb) {
