 catch (e) { errs.push('setLorebookEntries: ' + e.message); }
 }
 if (!created) throw new Error('ensureDynamicEntry 失败: ' + errs.join(' | '));
 // 兜底反查 uid
 if (_dynamicEntryUid == null) {
